// // This module implements a 4-bit register that loads the input data on the negative clock edge when the load signal is low.
module register (
  input clk,
  input load,
  input [3:0] data,
  output reg [3:0] q
);

  always @(posedge clk) begin
    if (load)
      q <= data;
  end

endmodule
